import { defineConfig } from "wxt";

// The MV3 manifest is generated by WXT into .output/<target>/manifest.json —
// there is no committed manifest.json.
export default defineConfig({
  modules: ["@wxt-dev/module-react"],
  manifest: ({ browser, command }) => {
    const isFirefox = browser === "firefox";
    /*
     * Origins allowed to post the device token back via runtime.sendMessage.
     * localhost is dev-only: shipping http://localhost/* in a published build
     * would let any localhost page reach the external-message surface.
     */
    const matches =
      command === "serve"
        ? ["https://captureflow.xyz/*", "http://localhost/*"]
        : ["https://captureflow.xyz/*"];
    return {
      name: "CaptureFlow",
      description: "Record your screen and share an instant link.",
      /*
       * `offscreen` (where getDisplayMedia runs) is Chromium-only, so gate it
       * for Firefox. `scripting` + `activeTab` inject the camera/mic permission
       * iframe on demand; activeTab keeps it warning-free (no broad host access).
       */
      permissions: isFirefox
        ? ["storage"]
        : ["storage", "offscreen", "scripting", "activeTab"],
      /*
       * Extension-context fetches to the API need host permission to skip
       * CORS/Private-Network-Access checks — Brave otherwise blocks extension
       * frames from reaching localhost in dev. Mirrors the
       * externally_connectable dev/prod split.
       */
      host_permissions: matches,
      // Firefox MV3 lacks web→extension messaging, so omit it there.
      ...(isFirefox ? {} : { externally_connectable: { matches } }),
      // The injected camera bubble, the permission-grant fallback, and the
      // in-page recorder overlay load these extension pages inside a web origin.
      ...(isFirefox
        ? {}
        : {
            web_accessible_resources: [
              {
                resources: ["bubble.html", "permissions.html", "popup.html"],
                matches: ["<all_urls>"],
              },
            ],
          }),
    };
  },
  hooks: {
    // The recorder opens as an in-page overlay from action.onClicked;
    // an anchored default_popup would swallow the click.
    "build:manifestGenerated": (_wxt, manifest) => {
      if (manifest.action) delete manifest.action.default_popup;
    },
  },
});
